&quot;); if (sockets.get(port1).containsKey(signalName)) { System.out.printf(&quot;SIGNAL %s, connected to %s, is from the following instruction(s):
&quot;,signalName,port1); sockets.get(port1).get(signalName).forEach((instrName) -&gt; System.out.printf(&quot;%s &quot;,instrName)); System.out.print(&quot;

